// src/components/Chatbot.js
import React, { useState, useRef, useEffect } from "react";
import axios from "axios";

const API_URL = "http://127.0.0.1:5000";

function Chatbot() {
  const [messages, setMessages] = useState([
    {
      sender: "bot",
      text: "Hello! Ask me about this project's technology, models, or goals.",
    },
  ]);
  const [input, setInput] = useState("");
  const [isLoading, setIsLoading] = useState(false);
  const messagesEndRef = useRef(null);

  // Effect to auto-scroll to the bottom when new messages are added
  useEffect(() => {
    messagesEndRef.current?.scrollIntoView({ behavior: "smooth" });
  }, [messages]);

  const sendMessage = async () => {
    if (!input.trim() || isLoading) return;
    const userMessage = input;
    setMessages((prev) => [...prev, { sender: "user", text: userMessage }]);
    setInput("");
    setIsLoading(true);

    try {
      const response = await axios.post(`${API_URL}/chat`, {
        message: userMessage,
      });
      setMessages((prev) => [
        ...prev,
        { sender: "bot", text: response.data.response },
      ]);
    } catch (err) {
      setMessages((prev) => [
        ...prev,
        { sender: "bot", text: "Error connecting to the chatbot API." },
      ]);
    } finally {
      setIsLoading(false);
    }
  };

  return (
    <div className="detector-container" style={{ maxWidth: "800px" }}>
      <h2 style={{ textAlign: "center" }}>🤖 Project AI Assistant</h2>
      <div
        style={{
          height: "500px",
          display: "flex",
          flexDirection: "column",
          border: "1px solid #ddd",
          borderRadius: "8px",
        }}
      >
        <div
          style={{
            flex: 1,
            overflowY: "auto",
            padding: "1rem",
            background: "#f9f9f9",
          }}
        >
          {messages.map((msg, index) => (
            <div
              key={index}
              style={{
                marginBottom: "1rem",
                display: "flex",
                justifyContent:
                  msg.sender === "user" ? "flex-end" : "flex-start",
              }}
            >
              <div
                style={{
                  background:
                    msg.sender === "user"
                      ? "var(--secondary-color)"
                      : "var(--light-gray)",
                  color: msg.sender === "user" ? "white" : "var(--text-color)",
                  padding: "0.5rem 1rem",
                  borderRadius: "15px",
                  maxWidth: "70%",
                }}
              >
                {msg.text}
              </div>
            </div>
          ))}
          {isLoading && (
            <div style={{ textAlign: "center" }}>
              <div className="spinner"></div>
            </div>
          )}
          <div ref={messagesEndRef} />
        </div>
        <div
          style={{
            display: "flex",
            padding: "1rem",
            borderTop: "1px solid #ddd",
          }}
        >
          <input
            type="text"
            value={input}
            onChange={(e) => setInput(e.target.value)}
            onKeyPress={(e) => e.key === "Enter" && sendMessage()}
            placeholder="Ask a question..."
            disabled={isLoading}
            style={{
              flex: 1,
              padding: "0.8rem",
              border: "1px solid #ccc",
              borderRadius: "8px",
              marginRight: "1rem",
            }}
          />
          <button
            onClick={sendMessage}
            className="btn"
            disabled={isLoading || !input.trim()}
          >
            Send
          </button>
        </div>
      </div>
    </div>
  );
}

export default Chatbot;
